import React, {useEffect, useState} from "react";

import { getUsers }
from "../api/admin";

import "../styles/Tables.css";
import "../styles/Cards.css";

function Admin() {

  const [users,
    setUsers] =
    useState([]);

  const loadUsers =
    async () => {

      try {

        const res =
          await getUsers();

        setUsers(
          res.data.data
        );

      } catch (err) {

        alert(
          err?.response?.data?.message ||
          "Không tải được danh sách người dùng"
        );

      }

    };

  useEffect(() => {
    loadUsers();
  }, []);

  return (

    <div className="page">

      <h2>
        👑 Admin Dashboard
      </h2>

      <div className="table-container">

        <table className="data-table">

          <thead>
            <tr>
              <th>ID</th>
              <th>Họ tên</th>
              <th>Email</th>
              <th>Role</th>
              <th>Ngày tạo</th>
            </tr>
          </thead>

          <tbody>

            {users.map((u) => (

              <tr
                key={u.user_id}
              >
                <td>
                  {u.user_id}
                </td>

                <td>
                  {u.full_name}
                </td>

                <td>
                  {u.email}
                </td>

                <td>
                  {u.role}
                </td>

                <td>
                  {new Date(
                    u.created_at
                  ).toLocaleDateString()}
                </td>

              </tr>

            ))}

          </tbody>

        </table>

      </div>

    </div>

  );

}

export default Admin;
